import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface DriverLocation {
  latitude: number;
  longitude: number;
}

interface QuickBiteData {
  orderStatus: string;
  estimatedDeliveryTime: string;
  driverLocation: DriverLocation;
}

export default function Widget() {
  const quickBiteData = response.data as QuickBiteData;
  const theme = response.meta.theme;
  const primaryColor = response.meta.primaryColor;
  const accentColor = response.meta.accentColor;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: theme === 'light' ? '#F5F7FA' : '#1E293B',
        color: theme === 'light' ? '#1F2937' : '#F8FAFC',
      }}
      elevation={3}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ fontWeight: 600, color: primaryColor }}>
              QuickBite Delivery
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              <Info sx={{ fontSize: 16, color: accentColor }} />
              <Typography variant="body2" sx={{ color: accentColor }}>
                {quickBiteData.orderStatus}
              </Typography>
            </Stack>
          </Box>

          <Stack direction="row" spacing={1} alignItems="center">
            <Typography variant="body2" sx={{ fontWeight: 500 }}>
              Estimated Time:
            </Typography>
            <Chip
              label={quickBiteData.estimatedDeliveryTime}
              sx={{
                backgroundColor: accentColor,
                color: '#FFFFFF',
                fontWeight: 600,
                fontSize: '12px',
                px: 1,
              }}
            />
          </Stack>

          <Box>
            <Typography variant="caption" sx={{ color: '#64748B' }}>
              Driver's Location:
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              Latitude: {quickBiteData.driverLocation.latitude}, Longitude: {quickBiteData.driverLocation.longitude}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
